import novamind_api as nm
# Social posts - competitor + complaints this week
posts = nm.analytics.get_social_posts(days=7, limit=100)
print('=== Recent Social Posts (last 7 days) ===')
comp_posts = []
our_posts = []
other = []
for p in posts[:60]:
    content = p.get('content','')
    if any(kw in content.lower() for kw in ['cloudpeak','quantum','rival','streamai','apex','tech','launch','model','beat','better than','competitor']):
        comp_posts.append(p)
    elif 'NovaMind' in content or 'nova' in content.lower():
        our_posts.append(p)
    else:
        other.append(p)

print(f'Competitor-ish: {len(comp_posts)}')
for p in comp_posts[:15]: print(f'  D{p.get(\"day\",\"?\")}: {p[\"content\"][:150]}')
print(f'\\nOur brand mentions: {len(our_posts)}')
for p in our_posts[:10]: print(f'  D{p.get(\"day\",\"?\")}: {p[\"content\"][:150]}')
print(f'\\nOther: {len(other)}')
for p in other[:10]: print(f'  D{p.get(\"day\",\"?\")}: {p[\"content\"][:150]}')
"

